import { useState, useMemo } from 'react';
import './Listings.css';

const ITEMS = [
  {
    id: 1,  name: 'Modular Folding Tables',      category: 'Furniture',   quantity: 120,
    location: 'LA Memorial Coliseum',     condition: 'Good',
    description: 'Heavy-duty rectangular tables used in athlete dining and media zones; stackable and easy to transport.',
  },
  {
    id: 2,  name: 'Athlete Village Bed Frames',  category: 'Furniture',   quantity: 350,
    location: 'UCLA Olympic Village',     condition: 'Like New',
    description: 'Single bed frames from athlete village dormitories, lightly used over a 3-week period.',
  },
  {
    id: 3,  name: 'LED Stage Lighting Rigs',     category: 'Electronics', quantity: 80,
    location: 'Crypto.com Arena',         condition: 'Good',
    description: 'Professional-grade LED lighting units used for ceremonies and broadcast; includes mounting hardware.',
  },
  {
    id: 4,  name: 'Event Canopy Structures',     category: 'Structures',  quantity: 45,
    location: 'UCLA Olympic Village',     condition: 'Like New',
    description: 'Large white canopy tents (10×20 ft) used as event and dining shelters across the Olympic Village.',
  },
  {
    id: 5,  name: 'Crowd Control Barriers',      category: 'Structures',  quantity: 200,
    location: 'Dignity Health Sports Park', condition: 'Fair',
    description: 'Interlocking steel crowd-management barriers used at venue perimeters; suitable for events and parades.',
  },
  {
    id: 6,  name: 'PA Speaker Systems',          category: 'Electronics', quantity: 30,
    location: 'Rose Bowl',                condition: 'Good',
    description: 'High-output portable PA speaker stacks used for field announcements and ceremonies.',
  },
  {
    id: 7,  name: 'Locker Units (6-Bay)',        category: 'Furniture',   quantity: 60,
    location: 'Long Beach Arena',         condition: 'Like New',
    description: 'Steel six-bay locker units from athlete changing facilities; ideal for schools and rec centers.',
  },
  {
    id: 8,  name: 'Diesel Portable Generators',  category: 'Equipment',   quantity: 25,
    location: 'Dignity Health Sports Park', condition: 'Good',
    description: 'Towable 20kW diesel generators used for temporary power at outdoor venue overlays.',
  },
  {
    id: 9,  name: 'Temporary Bleacher Sections', category: 'Structures',  quantity: 18,
    location: 'Rose Bowl',                condition: 'Fair',
    description: 'Modular aluminum bleacher sections (10-row, approx. 50 seats each) from temporary seating expansions.',
  },
  {
    id: 10, name: 'Broadcast Monitor Displays',  category: 'Electronics', quantity: 12,
    location: 'SoFi Stadium',             condition: 'Like New',
    description: 'Large-format production monitors used in broadcast compound control rooms; commercial-grade displays.',
  },
];

const CATEGORIES = ['All', ...Array.from(new Set(ITEMS.map((i) => i.category)))];

const CONDITION_COLORS = {
  'Like New': '#2e7d32',
  'Good':     '#1565c0',
  'Fair':     '#e65100',
};

export default function Listings() {
  const [search, setSearch]     = useState('');
  const [category, setCategory] = useState('All');

  const filtered = useMemo(() => {
    const q = search.toLowerCase();
    return ITEMS.filter((item) => {
      const matchesSearch =
        !q ||
        item.name.toLowerCase().includes(q) ||
        item.location.toLowerCase().includes(q);
      const matchesCategory = category === 'All' || item.category === category;
      return matchesSearch && matchesCategory;
    });
  }, [search, category]);

  return (
    <main className="listings-page">
      <div className="listings-header">
        <h1>Surplus Listings</h1>
        <p>Browse available materials from the LA28 Olympics.</p>
      </div>

      <div className="listings-controls">
        <input
          className="listings-search"
          type="search"
          placeholder="Search by name or location…"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
        <div className="listings-filters">
          {CATEGORIES.map((cat) => (
            <button
              key={cat}
              className={`filter-btn${category === cat ? ' active' : ''}`}
              onClick={() => setCategory(cat)}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {filtered.length === 0 ? (
        <p className="listings-empty">No items match your search.</p>
      ) : (
        <div className="listings-grid">
          {filtered.map((item) => (
            <div key={item.id} className="listing-card">
              <div className="card-top">
                <span className="card-category">{item.category}</span>
                <span
                  className="card-condition"
                  style={{ background: CONDITION_COLORS[item.condition] }}
                >
                  {item.condition}
                </span>
              </div>
              <h2 className="card-name">{item.name}</h2>
              <div className="card-meta">
                <div className="card-meta-row">
                  <span className="meta-label">Quantity</span>
                  <span className="meta-value">{item.quantity} units</span>
                </div>
                <div className="card-meta-row">
                  <span className="meta-label">Location</span>
                  <span className="meta-value">{item.location}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </main>
  );
}
